// Field Validation Gate: ensures required fields are populated before stage advance
const GHL_TOKEN = '{{ghl_token}}';
const LOCATION_ID = '{{ghl_location_id}}';
const BASE = 'https://services.leadconnectorhq.com';
const HEADERS = { 'Authorization': `Bearer ${GHL_TOKEN}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };

const REQUIRED_FIELDS = {
  '{{ghl_cf_labor_budget}}': 'Labor Budget',
  '{{ghl_cf_crew_payout}}': 'Crew Payout',
  '{{ghl_cf_gross_margin_pct}}': 'Gross Margin %',
  '{{ghl_cf_product_type}}': 'Product Type',
  '{{ghl_cf_crew}}': 'Crew Assignment'
};

const body = $input.first().json;
const oppId = body.opportunity_id || body.id;
if (!oppId) return [{ json: { status: 'error', message: 'No opportunity ID' } }];

const resp = await fetch(`${BASE}/opportunities/${oppId}`, { headers: HEADERS });
const opp = await resp.json();
const fields = opp.customFields || [];

const missing = [];
for (const [fieldId, fieldName] of Object.entries(REQUIRED_FIELDS)) {
  const field = fields.find(f => f.id === fieldId);
  if (!field || !field.value || field.value === '' || field.value === '0') {
    missing.push(fieldName);
  }
}

if (missing.length > 0) {
  return [{ json: { status: 'blocked', opportunity_id: oppId, name: opp.name, missing_fields: missing, message: `Cannot advance: missing ${missing.join(', ')}` } }];
}
return [{ json: { status: 'ok', opportunity_id: oppId, message: 'All required fields populated' } }];
